async function handleSystemCommand(payload) {
    console.log(`Executing action for 'system_command' event.`);
    console.log(`Command: ${payload.command}, Arguments: ${JSON.stringify(payload.args)}`);

    const { exec } = require('child_process');

    if (!payload.command) {
        throw new Error('System command is missing.');
    }

    // WARNING: Directly executing user-supplied commands can be a severe security risk!
    // Always sanitize inputs and prefer using `child_process.execFile` or `spawn`
    // with a whitelist of allowed commands and arguments.
    // This is for demonstration purposes only.
    const commandToExecute = `${payload.command} ${payload.args ? payload.args.join(' ') : ''}`;

    console.warn(`[SECURITY WARNING] Attempting to execute system command: "${commandToExecute}"`);

    return new Promise((resolve, reject) => {
        exec(commandToExecute, (error, stdout, stderr) => {
            if (error) {
                console.error(`Error executing command '${commandToExecute}':`, error);
                reject(error);
                return;
            }
            if (stderr) {
                console.error(`Command '${commandToExecute}' produced stderr:`, stderr);
            }
            console.log(`Command '${commandToExecute}' stdout:`, stdout);
            resolve();
        });
    });
}


